export const deleteFile = async (type, filename) => {
  const response = await fetch(`${API_URL}/api/upload/${type}/${filename}`, {
    method: 'DELETE',
    credentials: 'include'
  });

  if (!response.ok) {
    const error = await response.json();
    throw new Error(error.error || 'Delete failed');
  }

  return response.json();
};